Javascript.logic:
var value = Services.getValue(FirstWarrantNumber.dataBinding);
if (!CaseManUtils.isBlank(value))
{
	Services.setValue(REPRINT_PAGE, "");
	searchWarrants(FirstWarrantNumber);
	validateReprint();
}

Javascript.validate:
var ec = null;
var validReprint = Services.getValue(REPRINT_PAGE);
if ( !CaseManUtils.isBlank(validReprint) && validReprint == "false" )
{
	ec = ErrorCode.getErrorCode("CaseMan_WAREX_InvalidWarrantNumber");
}
return ec;

Javascript.miscCode:
			var SEARCH_RESULTS_XPATH_FIRST = PAGE_XPATH + "/tmp/FirstWarrantNumber/Warrants";
			var REPRINT_PAGE = PAGE_XPATH + "/tmp/ReprintPage";
			
			Status_RunReportButton.enableOn = [SEARCH_RESULTS_XPATH_FIRST, REPRINT_PAGE];		
			Status_RunReportButton.isEnabled = function()
			{
				var enabled = false;
				var reprint = Services.getValue(REPRINT_PAGE);
				if ( null == validateWarrants() && reprint == "true" )
				{
					enabled = true;
				}
				return enabled;
			}		

			function searchWarrants(fieldName)
			{
				var warrantNumber = Services.getValue(fieldName.dataBinding);	
				if (warrantNumber != null)
				{			
				    //Call Search Service now
					var params = new ServiceParams();
					var homeForeign = Services.getValue(HomeForeign.dataBinding);
					if (homeForeign != null)
					{
						if (homeForeign == "H") // Home Warrants
						{
							params.addSimpleParameter("warrantNumber", warrantNumber);
							
						}
						else // Foreign Warrant
						{
							params.addSimpleParameter("localNumber", warrantNumber);
						}
					}
					Services.callService("searchWarrants", params, fieldName, true);	
				}		
			}
			
			FirstWarrantNumber.onSuccess = function(dom) {
			    if(dom != null) {
			        var node = dom.selectSingleNode("/ds/Warrants");
			        Services.replaceNode(SEARCH_RESULTS_XPATH_FIRST, node);
			        
			        var count = Services.countNodes(SEARCH_RESULTS_XPATH_FIRST + "/Warrant");
			        if(count == 0) {
			           alert("Warrant Number\r\n" + Messages.NO_RESULTS_MESSAGE); 
			        } else if(count >= 1) {
			        }
			    }
			}
			
			function validateWarrants()
			{
				var errCode = null;
				var countFirst = Services.countNodes(SEARCH_RESULTS_XPATH_FIRST + "/Warrant");
				if(countFirst == 0) 
				{
		           	errCode = ErrorCode.getErrorCode("CaseMan_noLocalWarrantExists_Msg");
		        }
		        return errCode;
			}
			
			function validateReprint()
			{
				var firstWarrant = Services.getValue(FirstWarrantNumber.dataBinding);
				
				if ( !CaseManUtils.isBlank(firstWarrant) )
				{
					var homeForeign = Services.getValue(HomeForeign.dataBinding);
					var serviceName = ( homeForeign == "F" ) ? "getForeignWarrantsOfExecutionToReprinted" : "getWarrantsOfExecutionToReprinted";
					var params = new ServiceParams();
					params.addSimpleParameter("warrantNumber", firstWarrant);
					Services.callService(serviceName, params, Reprint, true);
				}
			}
			
			Reprint.onSuccess = function(dom) {
			    if(dom != null) {
					var reprint = dom.selectSingleNode("/ds/Warrant/Reprint").text;
					Services.setValue(REPRINT_PAGE, reprint);
			    }
			}
